const raw = ($json.query && $json.query.numero ? $json.query.numero : '').toString().trim();

if (!raw) {
  throw new Error('Numero de projet manquant. Utilisation: ?numero=1234');
}

const numeroChiffres = raw.replace(/[^0-9]/g, '');
const numeroNorm = raw.toUpperCase().replace(/\s+/g, '');

return [{ json: { numero_brut: raw, numero: numeroChiffres, numero_norm: numeroNorm } }];

const numero = $('Nettoyer le numéro de projet').first().json.numero;
const allRows = $input.all();

if (!allRows.length) {
  return [{ json: { _found: false, debug: 'Google Sheets vide ou inaccessible' } }];
}

// Normaliser un nom de colonne : retire accents, ponctuation, espaces multiples
function normCol(s) {
  return String(s).toLowerCase()
    .replace(/[àâä]/g, 'a')
    .replace(/[éèêë]/g, 'e')
    .replace(/[îï]/g, 'i')
    .replace(/[ôö]/g, 'o')
    .replace(/[ùûü]/g, 'u')
    .replace(/ç/g, 'c')
    .replace(/[^a-z0-9]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

// Noms normalises acceptes pour la colonne identifiant du projet / devis
const projColNorms = [
  'numero de projet', 'no de projet', 'n de projet', 'no projet',
  'numero devis', 'no devis', 'n devis', 'numero de devis', 'no de devis',
  'numero de soumission', 'no soumission', 'no de soumission',
  'devis', 'projet', 'numero', 'no', 'id'
];

// Valeur brute saisie (ex: "826", "D-826", "826-A")
const numeroBrut = $('Nettoyer le numéro de projet').first().json.numero_brut || numero;

// Teste si une valeur de cellule correspond au numero recherche
function matchesNumero(val) {
  const s = String(val || '').trim();
  if (!s) return false;
  // Correspondance exacte
  if (s === numeroBrut) return true;
  // Correspondance sur les chiffres uniquement
  const digitsOnly = s.replace(/[^0-9]/g, '');
  if (digitsOnly && digitsOnly === numero) return true;
  // Correspondance insensible a la casse sans espaces
  if (s.toUpperCase().replace(/\s+/g,'') === numeroBrut.toUpperCase().replace(/\s+/g,'')) return true;
  return false;
}

const firstRow = allRows[0].json;
const allKeys = Object.keys(firstRow);

// 1. Chercher d'abord par nom de colonne reconnu
let projKey = allKeys.find(function(k) {
  return projColNorms.indexOf(normCol(k)) !== -1;
});

let match = null;

if (projKey) {
  match = allRows.find(function(item) {
    return matchesNumero(item.json[projKey]);
  });
}

// 2. Fallback : si colonne non trouvee ou pas de match,
//    scanner TOUTES les colonnes a la recherche d'une valeur correspondante
if (!match) {
  for (let ki = 0; ki < allKeys.length; ki++) {
    const k = allKeys[ki];
    const found = allRows.find(function(item) {
      return matchesNumero(item.json[k]);
    });
    if (found) {
      match = found;
      projKey = k;
      break;
    }
  }
}

if (!match) {
  return [{ json: { _found: false, debug: 'Projet ' + numero + ' introuvable. Colonnes disponibles: ' + allKeys.join(', ') } }];
}

// Retourner toutes les colonnes de la ligne trouvee
const result = { _found: true };
Object.keys(match.json).forEach(function(k) {
  result[k] = match.json[k];
});
return [{ json: result }];

const r = $input.first().json;
const allKeys = Object.keys(r);

// ─── Helpers ─────────────────────────────────────────────────────
function normStr(s) {
  return String(s || '').toLowerCase()
    .replace(/[àâä]/g,'a').replace(/[éèêë]/g,'e')
    .replace(/[îï]/g,'i').replace(/[ôö]/g,'o')
    .replace(/[ùûü]/g,'u').replace(/ç/g,'c')
    .replace(/[^a-z0-9]/g,' ').replace(/\s+/g,' ').trim();
}

// Trouver la clé de colonne par mots-clés dans son en-tête
function findKey(keywords) {
  const normKws = keywords.map(normStr);
  return allKeys.find(function(k) {
    const nk = normStr(k);
    return normKws.some(function(kw) { return nk === kw || nk.indexOf(kw) !== -1; });
  }) || null;
}

// Lire une valeur : chercher par nom de colonne, puis fallback positionnel si valeur vide
function get(keywords, fallbackCol) {
  const key = findKey(keywords);
  let v = key ? r[key] : undefined;
  // Si la colonne trouvée par keyword est vide, essayer le fallback positionnel
  if ((v === undefined || v === null || String(v).trim() === '') && fallbackCol) {
    v = r[fallbackCol];
  }
  return (v !== undefined && v !== null && String(v).trim() !== '') ? String(v).trim() : '';
}

// Porte de garage : cherche explicitement 'porte de garage' ou 'garage'
// (doit matcher AVANT 'porte' seul pour éviter la confusion)
function getGarageDoors(fallbackCol) {
  const key = allKeys.find(function(k) {
    const nk = normStr(k);
    return nk.indexOf('porte de garage') !== -1 || nk.indexOf('porte garage') !== -1 || nk === 'garage';
  });
  let v = key ? r[key] : undefined;
  if ((v === undefined || v === null || String(v).trim() === '') && fallbackCol) {
    v = r[fallbackCol];
  }
  return (v !== undefined && v !== null && String(v).trim() !== '') ? String(v).trim() : '';
}

// Portes (entrées) : cherche 'porte' ou 'chassis' MAIS PAS 'porte de garage'
function getDoors(fallbackCol) {
  const key = allKeys.find(function(k) {
    const nk = normStr(k);
    return (nk.indexOf('porte') !== -1 || nk.indexOf('chassis') !== -1)
      && nk.indexOf('garage') === -1;
  });
  let v = key ? r[key] : undefined;
  if ((v === undefined || v === null || String(v).trim() === '') && fallbackCol) {
    v = r[fallbackCol];
  }
  return (v !== undefined && v !== null && String(v).trim() !== '') ? String(v).trim() : '';
}

const fmtCAD = function(n) {
  const num = parseFloat(String(n||0).replace(/[^0-9.]/g,''));
  if (isNaN(num)||num===0) return '';
  return new Intl.NumberFormat('fr-CA',{style:'currency',currency:'CAD'}).format(num);
};

const fmtDate = function(d) {
  if (!d) return '';
  const parts = String(d).match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/);
  if (parts) {
    const date = new Date(parseInt(parts[3]), parseInt(parts[2])-1, parseInt(parts[1]));
    return date.toLocaleDateString('fr-CA');
  }
  const date = new Date(d);
  if (isNaN(date)) return String(d);
  return date.toLocaleDateString('fr-CA');
};

// ─── Lecture du numéro de projet ────────────────────────────────
const jobNumBrut = get(['numero de devis','no de devis','numero de projet','no projet','devis','numero'], 'col_1');
const jobNum = jobNumBrut.replace(/[^0-9]/g,'') || jobNumBrut;

const subtotalRaw = parseFloat(get(['sous-total','subtotal','montant ht'], 'col_18')) || 0;
const acompteRaw  = parseFloat(get(['acompte','depot','versement'], 'col_19')) || 0;
const tps   = subtotalRaw * 0.05;
const tvq   = subtotalRaw * 0.09975;
const total = subtotalRaw + tps + tvq;
const solde = total - acompteRaw;

return [{
  json: {
    // Identification
    job_number:           jobNum,
    quote_number:         jobNum,
    // Client
    client_name:          get(['nom du client','nom client','client','nom'], 'col_2'),
    client_company:       get(['compagnie','entreprise','organisation'], 'col_23'),
    client_phone:         get(['telephone client','tel client','telephone','tel','phone'], 'col_3'),
    client_email:         get(['courriel client','courriel','email'], 'col_22'),
    // Chantier
    job_address:          get(['adresse du chantier','adresse chantier','adresse'], 'col_4'),
    end_date:             fmtDate(get(['date de fin','fin prevue'], 'col_21')),
    job_completion_date:  fmtDate(get(['date de fin','fin prevue'], 'col_21')),
    duration_days:        get(['duree prevue','duree','jours'], 'col_15'),
    // Travaux
    work_type:            get(['type de travaux','type travaux','travaux','service'], null),
    surfaces_raw:         get(['surfaces a peindre','surfaces','surface'], 'col_5'),
    surface_type:         get(['type de revetement','type revetement','revetement','materiau','materiaux'], 'col_6'),
    total_sqft:           get(['superficie','pi2','m2','pieds carres'], 'col_7'),
    doors_count:          getDoors('col_8'),
    floors_count:         get(['nb d etages','nombre d etages','etages a peindre','etages','etage','niveau'], 'col_13'),
    windows_count:        get(['fenetres','fenetre','nb de fenetres','vitres','fenetres a peindre','chassis fenetres','quantite fenetres','nb fenetres','nombre de fenetres'], 'col_10'),
    roofing:              get(['toiture en pi2','toiture','toit','surface toit'], 'col_11'),
    gouttieres_sqft:      get(['gouttieres soffites fascias','gouttieres','soffit','fascia','gouttiere'], 'col_12'),
    garage_doors_count:   getGarageDoors('col_9'),
    sanding_sqft:         get(['sablage'], 'col_14'),
    // Couleurs & instructions
    colors_raw:           get(['couleurs zones','couleurs','couleur'], 'col_16'),
    special_instructions: get(['instructions notes','instructions','notes','note'], 'col_17'),
    attention_points:     '',
    notes:                get(['notes additionnelles','notes add'], 'col_29'),
    // Contacts bureau
    office_contact_name:  get(['contact bureau','contact'], 'col_24'),
    office_contact_phone: get(['tel bureau','telephone bureau'], 'col_25'),
    supplier_name:        get(['fournisseur'], 'col_28'),
    // Finances
    subtotal:             fmtCAD(subtotalRaw),
    tps_amount:           fmtCAD(tps),
    tvq_amount:           fmtCAD(tvq),
    total_ttc:            fmtCAD(total),
    acompte_amount:       fmtCAD(acompteRaw),
    solde_amount:         fmtCAD(solde)
  }
}];
